// Template: Recordatorio 24h — leído desde plantillas_mensajes (categoria: recordatorios)
return items.map(item => {
  let body = item.json.plantilla_contenido || '👋 Hola {{nombre}}! Te recordamos tu turno mañana {{fecha_hora}} con {{medico_nombre}}.';
  const vars = item.json;
  body = body.replace(/\{\{\s*(\w+)\s*\}\}/g, (match, key) => {
    return vars[key] !== undefined ? String(vars[key]) : match;
  });
  return { json: { ...vars, body } };
});

// Template: Recordatorio 1h — leído desde plantillas_mensajes (categoria: recordatorios)
return items.map(item => {
  let body = item.json.plantilla_contenido || '⏰ Recordatorio {{nombre}}: en 1 hora tenés turno con {{medico_nombre}} ({{fecha_hora}}).';
  const vars = item.json;
  body = body.replace(/\{\{\s*(\w+)\s*\}\}/g, (match, key) => {
    return vars[key] !== undefined ? String(vars[key]) : match;
  });
  return { json: { ...vars, body } };
});

// Armar mensaje de alerta para el médico con los turnos no confirmados
// Agrupar por médico para enviar un solo mensaje
const groups = {};
for (const item of items) {
  const d = item.json;
  const key = d.medico_telefono || 'sin-telefono';
  if (!groups[key]) {
    groups[key] = {
      medico_nombre: d.medico_nombre,
      medico_telefono: d.medico_telefono,
      turnos: []
    };
  }
  groups[key].turnos.push(d);
}

const result = [];
for (const [tel, g] of Object.entries(groups)) {
  const lista = g.turnos.map(t =>
    `• ${t.nombre} ${t.apellido} — ${new Date(t.fecha_hora).toLocaleString('es-AR', { hour: '2-digit', minute: '2-digit', day: '2-digit', month: '2-digit' })}`
  ).join('\n');
  const body = `⚠️ Pacientes que NO confirmaron su turno:\n\n${lista}\n\nContactalos para confirmar asistencia.`;
  result.push({ json: { medico_nombre: g.medico_nombre, medico_telefono: g.medico_telefono, body, turnos: g.turnos } });
}
return result;
